import { useState, useCallback, useRef } from 'react';
import { 
    MatchResult, 
    Transaction, 
    Contributor, 
    Church, 
    Bank, 
    FileModel, 
    ComparisonType,
    ContributorFile,
    GroupedReportData,
    ReconciliationStatus
} from '../types';
import { 
    processFileContent, 
    parseContributors, 
    matchTransactions, 
    groupResultsByChurch,
    PLACEHOLDER_CHURCH
} from '../services/processingService';
import { IngestionOrchestrator } from '../core/engine/IngestionOrchestrator';
import { getAISuggestion } from '../services/geminiService';
import { useLiveListSync } from './useLiveListSync';

interface UseReconciliationProps {
    user: any;
    churches: Church[];
    banks: Bank[];
    fileModels: FileModel[];
    similarityLevel: number;
    dayTolerance: number;
    customIgnoreKeywords: string[];
    contributionKeywords: string[];
    learnedAssociations: any[];
    showToast: (msg: string, type: 'success' | 'error') => void;
    setIsLoading: (loading: boolean) => void;
    setActiveView: (view: any) => void;
}

export const useReconciliation = ({
    user,
    churches,
    banks,
    fileModels,
    similarityLevel,
    dayTolerance,
    customIgnoreKeywords,
    contributionKeywords,
    learnedAssociations,
    showToast,
    setIsLoading,
    setActiveView
}: UseReconciliationProps) => {

    const [activeBankFiles, setBankStatementFile] = useState<any[]>([]);
    const [contributorFiles, setContributorFiles] = useState<ContributorFile[]>([]);
    const [selectedBankIds, setSelectedBankIds] = useState<string[]>([]);
    const [matchResults, setMatchResults] = useState<MatchResult[]>([]);
    const [reportPreviewData, setReportPreviewData] = useState<{ income: GroupedReportData; expenses: GroupedReportData } | null>(null);
    const [activeReportId, setActiveReportId] = useState<string | null>(null);
    const [hasActiveSession, setHasActiveSession] = useState(false);
    const [comparisonType, setComparisonType] = useState<ComparisonType>('income');
    const [manualIdentificationTx, setManualIdentificationTx] = useState<Transaction | null>(null);
    const [bulkIdentificationTxs, setBulkIdentificationTxs] = useState<Transaction[]>([]);

    // 🔒 TRAVA DE REENTRADA DO PIPELINE
    const isProcessingListaViva = useRef(false);

    const [uiFeedback, setUiFeedback] = useState({
        loadingAiId: null as string | null,
        aiSuggestion: null as { id: string; name: string } | null,
        isRecompareModalOpen: false,
        pendingTraining: null as any | null
    });

    const { persistTransactions, clearRemoteList } = useLiveListSync({
        user,
        setBankStatementFile,
        setSelectedBankIds,
        showToast
    });

    const regenerateReportPreview = useCallback((results: MatchResult[]) => {
        const uniqueMap = new Map<string, MatchResult>();
        results.forEach(r => uniqueMap.set(r.transaction.id, r));
        const uniqueResults = Array.from(uniqueMap.values());

        const incomeResults = uniqueResults.filter(r => 
            r.transaction.amount >= 0 || 
            r.status === ReconciliationStatus.PENDING
        );

        const expenseResults = uniqueResults.filter(r => 
            r.transaction.amount < 0 && 
            r.status !== ReconciliationStatus.PENDING
        );

        setReportPreviewData({
            income: groupResultsByChurch(incomeResults),
            expenses: { 'all_expenses_group': expenseResults }
        });
    }, []);

    /**
     * 🛡️ PIPELINE DE UPLOAD BLINDADO (V12)
     * Implementa Trava de Reentrada e Deduplicação por Conteúdo.
     */
    const handleStatementUpload = useCallback(async (content: string, fileName: string, bankId: string, rawFile?: File) => {
        if (isProcessingListaViva.current) {
            console.log("[Pipeline:LOCK_BLOCKED] Abortando: Processamento em curso.");
            return;
        }

        console.log(`[Pipeline:START] Processando: ${fileName}`);
        isProcessingListaViva.current = true;
        setIsLoading(true);

        try {
            const result = await processFileContent(content, fileName, fileModels, customIgnoreKeywords);
            const incomingTransactions = result.transactions;

            if (incomingTransactions.length === 0) {
                showToast("Nenhuma transação encontrada.", "error");
                return;
            }

            // 🕵️ CHAVE ÚNICA COMPOSTA E FILTRO DE INSERT
            setBankStatementFile(prev => {
                const existingFile = prev.find(f => f.bankId === bankId);
                const existingTxs = existingFile?.processedTransactions || [];

                // Normalizar e gerar RowKey para existentes
                const existingKeys = new Set(existingTxs.map((t: Transaction) => 
                    `${t.date.trim()}|${t.description.trim().toLowerCase().replace(/\s+/g, ' ')}|${Number(t.amount).toFixed(2)}`
                ));

                // Filtrar apenas linhas inéditas
                const filteredNewTransactions = incomingTransactions.filter(t => {
                    const rowKey = `${t.date.trim()}|${t.description.trim().toLowerCase().replace(/\s+/g, ' ')}|${Number(t.amount).toFixed(2)}`;
                    if (existingKeys.has(rowKey)) {
                        console.log(`[ListaViva:DUPLICATE_BLOCKED] Linha ignorada: ${rowKey}`);
                        return false;
                    }
                    return true;
                });

                if (filteredNewTransactions.length === 0) {
                    console.log("[ListaViva:NO_NEW_ROWS] Nenhuma transação inédita encontrada.");
                    showToast("Todas as linhas já existem na Lista Viva.", "error");
                    return prev;
                }

                console.log(`[ListaViva:PERSIST_SAFE_COUNT] Incluindo ${filteredNewTransactions.length} registros.`);

                // Persistência Remota Segura
                persistTransactions(bankId, filteredNewTransactions);

                const updatedTxs = [...existingTxs, ...filteredNewTransactions];
                const otherBanks = prev.filter(f => f.bankId !== bankId);

                showToast(`${filteredNewTransactions.length} novas linhas adicionadas.`, "success");

                return [...otherBanks, { 
                    bankId, 
                    content, 
                    fileName, 
                    rawFile, 
                    processedTransactions: updatedTxs,
                    appliedMethod: result.method
                }];
            });

            setSelectedBankIds(prev => prev.includes(bankId) ? prev : [...prev, bankId]);

        } catch (error: any) {
            console.error("[Pipeline:ERROR]", error);
            showToast("Erro ao processar arquivo.", "error");
        } finally {
            setIsLoading(false);
            isProcessingListaViva.current = false;
            console.log("[Pipeline:END]");
        }
    }, [fileModels, customIgnoreKeywords, persistTransactions, showToast, setIsLoading]);

    const handleContributorsUpload = useCallback((content: string, fileName: string, churchId: string) => {
        const church = churches.find(c => c.id === churchId);
        if (!church) return;

        const contributors = parseContributors(content, customIgnoreKeywords, contributionKeywords);
        if (contributors.length === 0) {
            showToast("Nenhum contribuinte encontrado.", "error");
            return;
        }

        setContributorFiles(prev => {
            const filtered = prev.filter(f => f.churchId !== churchId);
            return [...filtered, { church, churchId, contributors, fileName }];
        });
        showToast(`Lista carregada (${contributors.length} nomes).`, "success");
    }, [churches, customIgnoreKeywords, contributionKeywords, showToast]);

    const removeContributorFile = useCallback((churchId: string) => {
        setContributorFiles(prev => prev.filter(f => f.churchId !== churchId));
    }, []);

    const toggleBankSelection = useCallback((bankId: string) => {
        setSelectedBankIds(prev => prev.includes(bankId) ? prev.filter(id => id !== bankId) : [...prev, bankId]);
    }, []);

    const importGmailTransactions = useCallback(async (transactions: Transaction[]) => {
        if (!user || transactions.length === 0 || isProcessingListaViva.current) return;

        isProcessingListaViva.current = true;
        setIsLoading(true);
        try {
            const bankId = 'gmail-sync';
            const result = await IngestionOrchestrator.processVirtualData('Gmail', transactions, customIgnoreKeywords);

            await persistTransactions(bankId, result.transactions);

            setBankStatementFile(prev => [
                ...prev.filter(f => f.bankId !== bankId),
                { 
                    bankId, 
                    fileName: 'Sincronização Gmail', 
                    processedTransactions: result.transactions,
                    content: '',
                    fingerprint: result.fingerprint
                }
            ]);
            setSelectedBankIds(prev => prev.includes(bankId) ? prev : [...prev, bankId]);
            showToast("Gmail sincronizado.", "success");
        } catch (e) {
            showToast("Erro na sincronização.", "error");
        } finally {
            setIsLoading(false);
            isProcessingListaViva.current = false;
        }
    }, [user, customIgnoreKeywords, persistTransactions, showToast, setIsLoading]);

    const removeBankStatementFile = useCallback((bankId: string) => {
        setBankStatementFile(prev => prev.filter(f => f.bankId !== bankId));
        setSelectedBankIds(prev => prev.filter(id => id !== bankId));
        clearRemoteList(bankId);
    }, [clearRemoteList]);

    const handleCompare = useCallback(async (
        overrideType?: ComparisonType, 
        overrideSimilarity?: number, 
        overrideTolerance?: number
    ) => {
        if (isProcessingListaViva.current) return;
        isProcessingListaViva.current = true;
        setIsLoading(true);

        try {
            const selectedFiles = activeBankFiles.filter(f => selectedBankIds.includes(f.bankId));
            const allTransactionsMap = new Map<string, Transaction>();

            const rawTxs = activeReportId 
                ? matchResults.map(r => r.transaction) 
                : selectedFiles.flatMap(f => f.processedTransactions || []);

            rawTxs.forEach(tx => allTransactionsMap.set(tx.id, tx));
            const allTransactions = Array.from(allTransactionsMap.values());

            if (allTransactions.length === 0 && !activeReportId) {
                showToast("Sem dados para comparar.", "error");
                return;
            }

            const finalType = overrideType || comparisonType;
            const finalSimilarity = overrideSimilarity !== undefined ? overrideSimilarity : similarityLevel;
            const finalTolerance = overrideTolerance !== undefined ? overrideTolerance : dayTolerance;

            let transactionsToMatch = allTransactions;
            if (finalType === 'income') {
                transactionsToMatch = allTransactions.filter(tx => tx.amount >= 0);
            } else if (finalType === 'expenses') {
                transactionsToMatch = allTransactions.filter(tx => tx.amount < 0);
            }

            const results = matchTransactions(
                transactionsToMatch,
                contributorFiles,
                { similarityThreshold: finalSimilarity, dayTolerance: finalTolerance },
                learnedAssociations,
                churches,
                customIgnoreKeywords
            );

            setMatchResults(results);
            regenerateReportPreview(results);
            setHasActiveSession(true);
            if (!activeReportId) setActiveView('reports');
            showToast("Conciliação concluída!", "success");
        } catch (error) {
            console.error("Erro na comparação:", error);
            showToast("Erro na conciliação.", "error");
        } finally {
            setIsLoading(false);
            isProcessingListaViva.current = false;
        }
    }, [activeBankFiles, selectedBankIds, contributorFiles, similarityLevel, dayTolerance, comparisonType, learnedAssociations, churches, customIgnoreKeywords, activeReportId, matchResults, showToast, setIsLoading, setActiveView, regenerateReportPreview]);

    const updateReportData = useCallback((updatedRow: MatchResult) => {
        setMatchResults(prev => {
            const next = [...prev];
            const index = next.findIndex(r => r.transaction.id === updatedRow.transaction.id);
            if (index !== -1) {
                next[index] = updatedRow;
            } else {
                next.push(updatedRow);
            }
            regenerateReportPreview(next);
            return next;
        });
    }, [regenerateReportPreview]);

    const revertMatch = useCallback((txId: string) => {
        setMatchResults(prev => {
            const next = [...prev];
            const idx = next.findIndex(r => r.transaction.id === txId);
            if (idx === -1) return prev;
            const old = next[idx];
            next[idx] = { 
                ...old, 
                status: ReconciliationStatus.UNIDENTIFIED, 
                church: PLACEHOLDER_CHURCH, 
                contributor: null, 
                matchMethod: undefined, 
                similarity: 0,
                contributorAmount: undefined
            };
            regenerateReportPreview(next);
            return next;
        });
    }, [regenerateReportPreview]);

    const resetReconciliation = useCallback(async () => {
        setMatchResults([]);
        setReportPreviewData(null);
        setActiveReportId(null);
        setHasActiveSession(false);
        setBankStatementFile([]);
        setContributorFiles([]);
        setSelectedBankIds([]);
        await clearRemoteList();
        showToast("Sistema resetado.", "success");
        setActiveView('upload');
    }, [clearRemoteList, showToast, setActiveView]);

    const handleAnalyze = useCallback(async (tx: Transaction, contributors: Contributor[]) => {
        setUiFeedback(prev => ({ ...prev, loadingAiId: tx.id }));
        try {
            const name = await getAISuggestion(tx, contributors);
            setUiFeedback(prev => ({ ...prev, aiSuggestion: { id: tx.id, name }, loadingAiId: null }));
        } catch (e) {
            setUiFeedback(prev => ({ ...prev, loadingAiId: null }));
        }
    }, []);

    return {
        activeBankFiles, contributorFiles, matchResults, reportPreviewData,
        activeReportId, setActiveReportId, hasActiveSession, setHasActiveSession,
        comparisonType, setComparisonType, selectedBankIds,
        manualIdentificationTx, setManualIdentificationTx,
        bulkIdentificationTxs, setBulkIdentificationTxs,
        importGmailTransactions,
        ...uiFeedback,
        setUiFeedback,
        handleStatementUpload, handleContributorsUpload, removeBankStatementFile,
        removeContributorFile, toggleBankSelection, handleCompare, resetReconciliation,
        revertMatch, updateReportData, handleAnalyze, setMatchResults, setReportPreviewData,
        setBankStatementFile,
        closeManualIdentify: () => {
            setManualIdentificationTx(null);
            setBulkIdentificationTxs([]);
        },
        findMatchResult: (id: string) => matchResults.find(r => r.transaction.id === id),
        removeTransaction: (id: string) => {
            setMatchResults(prev => {
                const next = prev.filter(r => r.transaction.id !== id);
                regenerateReportPreview(next);
                return next;
            });
        }
    };
};

import { useEffect, useCallback, useRef } from 'react';
import { Transaction } from '../types';
import { consolidationService } from '../services/ConsolidationService';

interface UseLiveListSyncProps {
    user: any;
    setBankStatementFile: (fn: (prev: any[]) => any[]) => void;
    setSelectedBankIds: (fn: (prev: string[]) => string[]) => void;
    showToast?: (msg: string, type: 'success' | 'error') => void;
}

export const useLiveListSync = ({
    user,
    setBankStatementFile,
    setSelectedBankIds,
    showToast
}: UseLiveListSyncProps) => {
    const isHydrating = useRef(false);
    const hasHydrated = useRef(false);
    const lastUserId = useRef<string | null>(null);

    // --- HIDRATAÇÃO: Recupera do DB ao iniciar ---
    useEffect(() => {
        if (!user || isHydrating.current || (hasHydrated.current && lastUserId.current === user.id)) return;

        const hydrate = async () => {
            isHydrating.current = true;
            lastUserId.current = user.id;

            try {
                console.log(`[Lista Viva] Iniciando recuperação para usuário: ${user.id}`);
                const dbTransactions = await consolidationService.getPendingTransactions(user.id);

                if (!dbTransactions || dbTransactions.length === 0) {
                    hasHydrated.current = true;
                    isHydrating.current = false;
                    return;
                }

                const groupedByBank: Record<string, Transaction[]> = {};
                const safeTransactions = dbTransactions.slice(0, 3000);

                safeTransactions.forEach((t: any) => {
                    const bankId = t.bank_id || 'unknown';
                    const tx: Transaction = {
                        id: t.id,
                        date: t.transaction_date,
                        description: t.description,
                        rawDescription: t.description,
                        amount: t.amount,
                        originalAmount: String(t.amount.toFixed(2)),
                        contributionType: t.type === 'income' ? 'ENTRADA' : 'SAÍDA',
                        cleanedDescription: t.description
                    };
                    if (!groupedByBank[bankId]) groupedByBank[bankId] = [];
                    groupedByBank[bankId].push(tx);
                });

                const restoredFiles = Object.entries(groupedByBank).map(([bankId, txs]) => ({
                    bankId,
                    content: '',
                    fileName: `Lista Viva (Recuperada)`,
                    rawFile: undefined,
                    processedTransactions: txs,
                    isRestored: true
                }));

                setBankStatementFile(() => restoredFiles);
                setSelectedBankIds(() => restoredFiles.map(f => f.bankId));

                hasHydrated.current = true;
                console.log(`[Lista Viva] ${safeTransactions.length} registros restaurados.`);
            } catch (err) {
                console.error("[Lista Viva] Erro crítico na hidratação:", err);
            } finally {
                isHydrating.current = false;
            }
        };

        hydrate();
    }, [user, setBankStatementFile, setSelectedBankIds]);

    /**
     * 🛡️ PERSISTÊNCIA BLINDADA COM CHAVE COMPOSTA (V13)
     */
    const persistTransactions = useCallback(async (bankId: string, transactions: Transaction[]) => {
        if (!user || transactions.length === 0) return;

        try {
            // 1. OBTER ESTADO ATUAL PARA DEDUPLICAÇÃO
            const currentDbTxs = await consolidationService.getPendingTransactions(user.id);

            // Gerador de Chave Única: Normaliza Data, Nome e Valor
            const buildKey = (date: string, desc: string, amt: number) => {
                const d = date.trim();
                const n = desc.trim().toLowerCase().replace(/\s+/g, ' ');
                const v = Number(amt).toFixed(2);
                return `${d}|${n}|${v}`;
            };

            const existingKeys = new Set(currentDbTxs.map((t: any) => 
                buildKey(t.transaction_date, t.description, t.amount)
            ));

            // 2. FILTRAR ARRAY FINAL (Insert Guard)
            const uniqueToPersist = transactions.filter(t => {
                const rowKey = buildKey(t.date, t.description, t.amount);
                if (existingKeys.has(rowKey)) {
                    console.log(`[ListaViva:DUPLICATE_BLOCKED] Ignorando persistência de linha idêntica: ${rowKey}`);
                    return false;
                }
                existingKeys.add(rowKey); // Previne duplicatas dentro do próprio lote novo
                return true;
            });

            if (uniqueToPersist.length === 0) {
                console.log("[ListaViva:NO_NEW_ROWS] Abortando persistência: Lote sem novidades.");
                return;
            }

            console.log(`[ListaViva:PERSIST_SAFE_COUNT] Enviando ${uniqueToPersist.length} registros inéditos.`);

            // 3. PERSISTÊNCIA EM BLOCO
            const chunkSize = 100;
            for (let i = 0; i < uniqueToPersist.length; i += chunkSize) {
                const chunk = uniqueToPersist.slice(i, i + chunkSize);
                const data = chunk.map(t => ({
                    transaction_date: t.date,
                    amount: t.amount,
                    description: t.description,
                    type: (t.amount >= 0 ? 'income' : 'expense') as 'income' | 'expense',
                    pix_key: null,
                    source: 'file' as 'file',
                    user_id: user.id,
                    bank_id: bankId.length > 10 ? bankId : null 
                }));
                await consolidationService.addTransactions(data);
            }
        } catch (e) {
            console.warn("[ListaViva:PERSIST_ERROR] Falha na sincronização", e);
        }
    }, [user]);

    const clearRemoteList = useCallback(async (bankId?: string) => {
        if (!user) return;
        try {
            await consolidationService.deletePendingTransactions(user.id, bankId);
            hasHydrated.current = false;
        } catch (e) {
            console.error("[Lista Viva] Erro ao limpar banco remoto:", e);
        }
    }, [user]);

    return { persistTransactions, clearRemoteList };
};

import { useState, useCallback, useRef } from 'react';
import { 
    MatchResult, 
    Transaction, 
    Contributor, 
    Church, 
    Bank, 
    FileModel, 
    ComparisonType,
    ContributorFile,
    GroupedReportData,
    ReconciliationStatus
} from '../types';
import { 
    processFileContent, 
    parseContributors, 
    matchTransactions, 
    groupResultsByChurch,
    PLACEHOLDER_CHURCH
} from '../services/processingService';
import { IngestionOrchestrator } from '../core/engine/IngestionOrchestrator';
import { getAISuggestion } from '../services/geminiService';
import { useLiveListSync } from './useLiveListSync';

interface UseReconciliationProps {
    user: any;
    churches: Church[];
    banks: Bank[];
    fileModels: FileModel[];
    similarityLevel: number;
    dayTolerance: number;
    customIgnoreKeywords: string[];
    contributionKeywords: string[];
    learnedAssociations: any[];
    showToast: (msg: string, type: 'success' | 'error') => void;
    setIsLoading: (loading: boolean) => void;
    setActiveView: (view: any) => void;
}

export const useReconciliation = ({
    user,
    churches,
    banks,
    fileModels,
    similarityLevel,
    dayTolerance,
    customIgnoreKeywords,
    contributionKeywords,
    learnedAssociations,
    showToast,
    setIsLoading,
    setActiveView
}: UseReconciliationProps) => {

    const [activeBankFiles, setBankStatementFile] = useState<any[]>([]);
    const [contributorFiles, setContributorFiles] = useState<ContributorFile[]>([]);
    const [selectedBankIds, setSelectedBankIds] = useState<string[]>([]);
    const [matchResults, setMatchResults] = useState<MatchResult[]>([]);
    const [reportPreviewData, setReportPreviewData] = useState<{ income: GroupedReportData; expenses: GroupedReportData } | null>(null);
    const [activeReportId, setActiveReportId] = useState<string | null>(null);
    const [hasActiveSession, setHasActiveSession] = useState(false);
    const [comparisonType, setComparisonType] = useState<ComparisonType>('income');
    const [manualIdentificationTx, setManualIdentificationTx] = useState<Transaction | null>(null);
    const [bulkIdentificationTxs, setBulkIdentificationTxs] = useState<Transaction[]>([]);

    // 🔒 1. TRAVA DE REENTRADA DO PIPELINE
    const isProcessingListaViva = useRef(false);

    const [uiFeedback, setUiFeedback] = useState({
        loadingAiId: null as string | null,
        aiSuggestion: null as { id: string; name: string } | null,
        isRecompareModalOpen: false,
        pendingTraining: null as any | null
    });

    const { persistTransactions, clearRemoteList } = useLiveListSync({
        user,
        setBankStatementFile,
        setSelectedBankIds,
        showToast
    });

    const regenerateReportPreview = useCallback((results: MatchResult[]) => {
        const uniqueMap = new Map<string, MatchResult>();
        results.forEach(r => uniqueMap.set(r.transaction.id, r));
        const uniqueResults = Array.from(uniqueMap.values());

        const incomeResults = uniqueResults.filter(r => 
            r.transaction.amount >= 0 || 
            r.status === ReconciliationStatus.PENDING
        );

        const expenseResults = uniqueResults.filter(r => 
            r.transaction.amount < 0 && 
            r.status !== ReconciliationStatus.PENDING
        );

        setReportPreviewData({
            income: groupResultsByChurch(incomeResults),
            expenses: { 'all_expenses_group': expenseResults }
        });
    }, []);

    /**
     * 🛡️ PIPELINE DE UPLOAD BLINDADO (V14)
     * Implementa Bloqueio de Reentrada e Filtro de Inserção com Chave Composta.
     */
    const handleStatementUpload = useCallback(async (content: string, fileName: string, bankId: string, rawFile?: File) => {
        // [Pipeline:LOCK_CHECK]
        if (isProcessingListaViva.current) {
            console.log("[Pipeline:LOCK_BLOCKED] Abortando execução paralela.");
            return;
        }

        console.log(`[Pipeline:START] Processando arquivo: ${fileName}`);
        isProcessingListaViva.current = true;
        setIsLoading(true);

        try {
            const result = await processFileContent(content, fileName, fileModels, customIgnoreKeywords);
            const incomingTransactions = result.transactions;

            if (incomingTransactions.length === 0) {
                showToast("Nenhuma transação encontrada.", "error");
                return;
            }

            // 🕵️ 2. CHAVE ÚNICA COMPOSTA NA LISTA VIVA
            const buildRowKey = (t: Transaction) => {
                const safeDate = t.date.trim();
                const safeName = t.description.trim().toLowerCase().replace(/\s+/g, ' ');
                const safeValue = Number(t.amount).toFixed(2);
                return `${safeDate}|${safeName}|${safeValue}`;
            };

            // 3. ÍNDICE REAL DOS EXISTENTES (Lê estado atual para comparação)
            // Buscamos as transações atuais para este banco específico
            const currentFiles = [...activeBankFiles];
            const existingBankFile = currentFiles.find(f => f.bankId === bankId);
            const existingTxs = existingBankFile?.processedTransactions || [];

            const existingMap = new Map();
            existingTxs.forEach((t: Transaction) => existingMap.set(buildRowKey(t), true));

            // 4. FILTRO FORÇADO DE INSERT
            const filteredNewTransactions = incomingTransactions.filter(t => {
                const rowKey = buildRowKey(t);
                if (existingMap.has(rowKey)) {
                    console.log(`[ListaViva:DUPLICATE_BLOCKED] Ignorado: ${rowKey}`);
                    return false;
                }
                existingMap.set(rowKey, true);
                return true;
            });

            if (filteredNewTransactions.length === 0) {
                console.log("[ListaViva:NO_NEW_ROWS] Abortando persistência: Lote duplicado.");
                showToast("Este arquivo já foi processado ou não contém novas linhas.", "error");
                return;
            }

            // 5. BLOQUEIO DE DUPLICAÇÃO NO STORAGE (Chamada fora do setter de estado)
            console.log(`[ListaViva:PERSIST_SAFE_COUNT] Persistindo ${filteredNewTransactions.length} novas linhas.`);
            await persistTransactions(bankId, filteredNewTransactions);

            // 6. ATUALIZAÇÃO DA UI (Apenas após persistência bem sucedida)
            setBankStatementFile(prev => {
                const otherBanks = prev.filter(f => f.bankId !== bankId);
                const updatedTxs = [...existingTxs, ...filteredNewTransactions];

                return [...otherBanks, { 
                    bankId, 
                    content, 
                    fileName, 
                    rawFile, 
                    processedTransactions: updatedTxs,
                    appliedMethod: result.method
                }];
            });

            setSelectedBankIds(prev => prev.includes(bankId) ? prev : [...prev, bankId]);
            showToast(`${filteredNewTransactions.length} registros adicionados.`, "success");

        } catch (error: any) {
            console.error("[Pipeline:ERROR]", error);
            showToast("Erro ao processar arquivo.", "error");
        } finally {
            setIsLoading(false);
            isProcessingListaViva.current = false; // [Pipeline:FINALLY]
            console.log("[Pipeline:END]");
        }
    }, [activeBankFiles, fileModels, customIgnoreKeywords, persistTransactions, showToast, setIsLoading]);

    const handleContributorsUpload = useCallback((content: string, fileName: string, churchId: string) => {
        const church = churches.find(c => c.id === churchId);
        if (!church) return;

        const contributors = parseContributors(content, customIgnoreKeywords, contributionKeywords);
        if (contributors.length === 0) {
            showToast("Nenhum contribuinte encontrado.", "error");
            return;
        }

        setContributorFiles(prev => {
            const filtered = prev.filter(f => f.churchId !== churchId);
            return [...filtered, { church, churchId, contributors, fileName }];
        });
        showToast(`Lista carregada (${contributors.length} nomes).`, "success");
    }, [churches, customIgnoreKeywords, contributionKeywords, showToast]);

    const removeContributorFile = useCallback((churchId: string) => {
        setContributorFiles(prev => prev.filter(f => f.churchId !== churchId));
    }, []);

    const toggleBankSelection = useCallback((bankId: string) => {
        setSelectedBankIds(prev => prev.includes(bankId) ? prev.filter(id => id !== bankId) : [...prev, bankId]);
    }, []);

    const importGmailTransactions = useCallback(async (transactions: Transaction[]) => {
        if (!user || transactions.length === 0 || isProcessingListaViva.current) return;

        isProcessingListaViva.current = true;
        setIsLoading(true);
        try {
            const bankId = 'gmail-sync';
            const result = await IngestionOrchestrator.processVirtualData('Gmail', transactions, customIgnoreKeywords);

            await persistTransactions(bankId, result.transactions);

            setBankStatementFile(prev => [
                ...prev.filter(f => f.bankId !== bankId),
                { 
                    bankId, 
                    fileName: 'Sincronização Gmail', 
                    processedTransactions: result.transactions,
                    content: '',
                    fingerprint: result.fingerprint
                }
            ]);
            setSelectedBankIds(prev => prev.includes(bankId) ? prev : [...prev, bankId]);
            showToast("Gmail sincronizado.", "success");
        } catch (e) {
            showToast("Erro na sincronização.", "error");
        } finally {
            setIsLoading(false);
            isProcessingListaViva.current = false;
        }
    }, [user, customIgnoreKeywords, persistTransactions, showToast, setIsLoading]);

    const removeBankStatementFile = useCallback((bankId: string) => {
        setBankStatementFile(prev => prev.filter(f => f.bankId !== bankId));
        setSelectedBankIds(prev => prev.filter(id => id !== bankId));
        clearRemoteList(bankId);
    }, [clearRemoteList]);

    const handleCompare = useCallback(async (
        overrideType?: ComparisonType, 
        overrideSimilarity?: number, 
        overrideTolerance?: number
    ) => {
        if (isProcessingListaViva.current) return;
        isProcessingListaViva.current = true;
        setIsLoading(true);

        try {
            const selectedFiles = activeBankFiles.filter(f => selectedBankIds.includes(f.bankId));
            const allTransactionsMap = new Map<string, Transaction>();

            const rawTxs = activeReportId 
                ? matchResults.map(r => r.transaction) 
                : selectedFiles.flatMap(f => f.processedTransactions || []);

            rawTxs.forEach(tx => allTransactionsMap.set(tx.id, tx));
            const allTransactions = Array.from(allTransactionsMap.values());

            if (allTransactions.length === 0 && !activeReportId) {
                showToast("Sem dados para comparar.", "error");
                return;
            }

            const finalType = overrideType || comparisonType;
            const finalSimilarity = overrideSimilarity !== undefined ? overrideSimilarity : similarityLevel;
            const finalTolerance = overrideTolerance !== undefined ? overrideTolerance : dayTolerance;

            let transactionsToMatch = allTransactions;
            if (finalType === 'income') {
                transactionsToMatch = allTransactions.filter(tx => tx.amount >= 0);
            } else if (finalType === 'expenses') {
                transactionsToMatch = allTransactions.filter(tx => tx.amount < 0);
            }

            const results = matchTransactions(
                transactionsToMatch,
                contributorFiles,
                { similarityThreshold: finalSimilarity, dayTolerance: finalTolerance },
                learnedAssociations,
                churches,
                customIgnoreKeywords
            );

            setMatchResults(results);
            regenerateReportPreview(results);
            setHasActiveSession(true);
            if (!activeReportId) setActiveView('reports');
            showToast("Conciliação concluída!", "success");
        } catch (error) {
            console.error("Erro na comparação:", error);
            showToast("Erro na conciliação.", "error");
        } finally {
            setIsLoading(false);
            isProcessingListaViva.current = false;
        }
    }, [activeBankFiles, selectedBankIds, contributorFiles, similarityLevel, dayTolerance, comparisonType, learnedAssociations, churches, customIgnoreKeywords, activeReportId, matchResults, showToast, setIsLoading, setActiveView, regenerateReportPreview]);

    const updateReportData = useCallback((updatedRow: MatchResult) => {
        setMatchResults(prev => {
            const next = [...prev];
            const index = next.findIndex(r => r.transaction.id === updatedRow.transaction.id);
            if (index !== -1) {
                next[index] = updatedRow;
            } else {
                next.push(updatedRow);
            }
            regenerateReportPreview(next);
            return next;
        });
    }, [regenerateReportPreview]);

    const revertMatch = useCallback((txId: string) => {
        setMatchResults(prev => {
            const next = [...prev];
            const idx = next.findIndex(r => r.transaction.id === txId);
            if (idx === -1) return prev;
            const old = next[idx];
            next[idx] = { 
                ...old, 
                status: ReconciliationStatus.UNIDENTIFIED, 
                church: PLACEHOLDER_CHURCH, 
                contributor: null, 
                matchMethod: undefined, 
                similarity: 0,
                contributorAmount: undefined
            };
            regenerateReportPreview(next);
            return next;
        });
    }, [regenerateReportPreview]);

    const resetReconciliation = useCallback(async () => {
        setMatchResults([]);
        setReportPreviewData(null);
        setActiveReportId(null);
        setHasActiveSession(false);
        setBankStatementFile([]);
        setContributorFiles([]);
        setSelectedBankIds([]);
        await clearRemoteList();
        showToast("Sistema resetado.", "success");
        setActiveView('upload');
    }, [clearRemoteList, showToast, setActiveView]);

    const handleAnalyze = useCallback(async (tx: Transaction, contributors: Contributor[]) => {
        setUiFeedback(prev => ({ ...prev, loadingAiId: tx.id }));
        try {
            const name = await getAISuggestion(tx, contributors);
            setUiFeedback(prev => ({ ...prev, aiSuggestion: { id: tx.id, name }, loadingAiId: null }));
        } catch (e) {
            setUiFeedback(prev => ({ ...prev, loadingAiId: null }));
        }
    }, []);

    return {
        activeBankFiles, contributorFiles, matchResults, reportPreviewData,
        activeReportId, setActiveReportId, hasActiveSession, setHasActiveSession,
        comparisonType, setComparisonType, selectedBankIds,
        manualIdentificationTx, setManualIdentificationTx,
        bulkIdentificationTxs, setBulkIdentificationTxs,
        importGmailTransactions,
        ...uiFeedback,
        setUiFeedback,
        handleStatementUpload, handleContributorsUpload, removeBankStatementFile,
        removeContributorFile, toggleBankSelection, handleCompare, resetReconciliation,
        revertMatch, updateReportData, handleAnalyze, setMatchResults, setReportPreviewData,
        setBankStatementFile,
        closeManualIdentify: () => {
            setManualIdentificationTx(null);
            setBulkIdentificationTxs([]);
        },
        findMatchResult: (id: string) => matchResults.find(r => r.transaction.id === id),
        removeTransaction: (id: string) => {
            setMatchResults(prev => {
                const next = prev.filter(r => r.transaction.id !== id);
                regenerateReportPreview(next);
                return next;
            });
        }
    };
};

import { useEffect, useCallback, useRef } from 'react';
import { Transaction } from '../types';
import { consolidationService } from '../services/ConsolidationService';

interface UseLiveListSyncProps {
    user: any;
    setBankStatementFile: (fn: (prev: any[]) => any[]) => void;
    setSelectedBankIds: (fn: (prev: string[]) => string[]) => void;
    showToast?: (msg: string, type: 'success' | 'error') => void;
}

export const useLiveListSync = ({
    user,
    setBankStatementFile,
    setSelectedBankIds,
    showToast
}: UseLiveListSyncProps) => {
    const isHydrating = useRef(false);
    const hasHydrated = useRef(false);
    const lastUserId = useRef<string | null>(null);

    // --- HIDRATAÇÃO: Recupera do DB ao iniciar ---
    useEffect(() => {
        if (!user || isHydrating.current || (hasHydrated.current && lastUserId.current === user.id)) return;

        const hydrate = async () => {
            isHydrating.current = true;
            lastUserId.current = user.id;

            try {
                console.log(`[Lista Viva] Iniciando recuperação para usuário: ${user.id}`);
                const dbTransactions = await consolidationService.getPendingTransactions(user.id);

                if (!dbTransactions || dbTransactions.length === 0) {
                    hasHydrated.current = true;
                    isHydrating.current = false;
                    return;
                }

                const groupedByBank: Record<string, Transaction[]> = {};
                const safeTransactions = dbTransactions.slice(0, 3000);

                safeTransactions.forEach((t: any) => {
                    const bankId = t.bank_id || 'unknown';
                    const tx: Transaction = {
                        id: t.id,
                        date: t.transaction_date,
                        description: t.description,
                        rawDescription: t.description,
                        amount: t.amount,
                        originalAmount: String(t.amount.toFixed(2)),
                        contributionType: t.type === 'income' ? 'ENTRADA' : 'SAÍDA',
                        cleanedDescription: t.description
                    };
                    if (!groupedByBank[bankId]) groupedByBank[bankId] = [];
                    groupedByBank[bankId].push(tx);
                });

                const restoredFiles = Object.entries(groupedByBank).map(([bankId, txs]) => ({
                    bankId,
                    content: '',
                    fileName: `Lista Viva (Recuperada)`,
                    rawFile: undefined,
                    processedTransactions: txs,
                    isRestored: true
                }));

                setBankStatementFile(() => restoredFiles);
                setSelectedBankIds(() => restoredFiles.map(f => f.bankId));

                hasHydrated.current = true;
                console.log(`[Lista Viva] ${safeTransactions.length} registros restaurados.`);
            } catch (err) {
                console.error("[Lista Viva] Erro crítico na hidratação:", err);
            } finally {
                isHydrating.current = false;
            }
        };

        hydrate();
    }, [user, setBankStatementFile, setSelectedBankIds]);

    /**
     * 🛡️ PERSISTÊNCIA BLINDADA COM CHAVE COMPOSTA (V15)
     */
    const persistTransactions = useCallback(async (bankId: string, transactions: Transaction[]) => {
        if (!user || transactions.length === 0) return;

        try {
            // 1. OBTER ESTADO ATUAL PARA DEDUPLICAÇÃO
            const currentDbTxs = await consolidationService.getPendingTransactions(user.id);

            // Gerador de Chave Única: Normaliza Data, Nome e Valor conforme regras
            const buildKey = (date: string, desc: string, amt: number) => {
                const safeDate = date.trim();
                const safeName = desc.trim().toLowerCase().replace(/\s+/g, ' ');
                const safeValue = Number(amt).toFixed(2);
                return `${safeDate}|${safeName}|${safeValue}`;
            };

            const existingKeysMap = new Map();
            currentDbTxs.forEach((t: any) => {
                existingKeysMap.set(buildKey(t.transaction_date, t.description, t.amount), true);
            });

            // 2. FILTRAR ARRAY FINAL (Insert Guard)
            const uniqueToPersist = transactions.filter(t => {
                const rowKey = buildKey(t.date, t.description, t.amount);
                if (existingKeysMap.has(rowKey)) {
                    console.log(`[ListaViva:DUPLICATE_BLOCKED] Ignorando persistência: ${rowKey}`);
                    return false;
                }
                existingKeysMap.set(rowKey, true); // Evita duplicatas no mesmo lote
                return true;
            });

            if (uniqueToPersist.length === 0) {
                console.log("[ListaViva:NO_NEW_ROWS] Abortando persistência: Nenhuma linha inédita.");
                return;
            }

            console.log(`[ListaViva:PERSIST_SAFE_COUNT] Enviando ${uniqueToPersist.length} registros inéditos.`);

            // 3. PERSISTÊNCIA EM BLOCO
            const chunkSize = 100;
            for (let i = 0; i < uniqueToPersist.length; i += chunkSize) {
                const chunk = uniqueToPersist.slice(i, i + chunkSize);
                const data = chunk.map(t => ({
                    transaction_date: t.date,
                    amount: t.amount,
                    description: t.description,
                    type: (t.amount >= 0 ? 'income' : 'expense') as 'income' | 'expense',
                    pix_key: null,
                    source: 'file' as 'file',
                    user_id: user.id,
                    bank_id: bankId.length > 10 ? bankId : null 
                }));
                await consolidationService.addTransactions(data);
            }
        } catch (e) {
            console.warn("[ListaViva:PERSIST_ERROR] Falha na sincronização remota", e);
        }
    }, [user]);

    const clearRemoteList = useCallback(async (bankId?: string) => {
        if (!user) return;
        try {
            await consolidationService.deletePendingTransactions(user.id, bankId);
            hasHydrated.current = false;
        } catch (e) {
            console.error("[Lista Viva] Erro ao limpar banco remoto:", e);
        }
    }, [user]);

    return { persistTransactions, clearRemoteList };
};

import { useState, useCallback, useRef } from 'react';
import { 
    MatchResult, 
    Transaction, 
    Contributor, 
    Church, 
    Bank, 
    FileModel, 
    ComparisonType,
    ContributorFile,
    GroupedReportData,
    ReconciliationStatus
} from '../types';
import { 
    processFileContent, 
    parseContributors, 
    matchTransactions, 
    groupResultsByChurch,
    PLACEHOLDER_CHURCH
} from '../services/processingService';
import { IngestionOrchestrator } from '../core/engine/IngestionOrchestrator';
import { getAISuggestion } from '../services/geminiService';
import { useLiveListSync } from './useLiveListSync';

interface UseReconciliationProps {
    user: any;
    churches: Church[];
    banks: Bank[];
    fileModels: FileModel[];
    similarityLevel: number;
    dayTolerance: number;
    customIgnoreKeywords: string[];
    contributionKeywords: string[];
    learnedAssociations: any[];
    showToast: (msg: string, type: 'success' | 'error') => void;
    setIsLoading: (loading: boolean) => void;
    setActiveView: (view: any) => void;
}

export const useReconciliation = ({
    user,
    churches,
    banks,
    fileModels,
    similarityLevel,
    dayTolerance,
    customIgnoreKeywords,
    contributionKeywords,
    learnedAssociations,
    showToast,
    setIsLoading,
    setActiveView
}: UseReconciliationProps) => {

    const [activeBankFiles, setBankStatementFile] = useState<any[]>([]);
    const [contributorFiles, setContributorFiles] = useState<ContributorFile[]>([]);
    const [selectedBankIds, setSelectedBankIds] = useState<string[]>([]);
    const [matchResults, setMatchResults] = useState<MatchResult[]>([]);
    const [reportPreviewData, setReportPreviewData] = useState<{ income: GroupedReportData; expenses: GroupedReportData } | null>(null);
    const [activeReportId, setActiveReportId] = useState<string | null>(null);
    const [hasActiveSession, setHasActiveSession] = useState(false);
    const [comparisonType, setComparisonType] = useState<ComparisonType>('income');
    const [manualIdentificationTx, setManualIdentificationTx] = useState<Transaction | null>(null);
    const [bulkIdentificationTxs, setBulkIdentificationTxs] = useState<Transaction[]>([]);

    // 🔒 1. TRAVA DE REENTRADA DO PIPELINE (Proteção contra loops)
    const isProcessingListaViva = useRef(false);

    const [uiFeedback, setUiFeedback] = useState({
        loadingAiId: null as string | null,
        aiSuggestion: null as { id: string; name: string } | null,
        isRecompareModalOpen: false,
        pendingTraining: null as any | null
    });

    const { persistTransactions, clearRemoteList } = useLiveListSync({
        user,
        setBankStatementFile,
        setSelectedBankIds,
        showToast
    });

    const regenerateReportPreview = useCallback((results: MatchResult[]) => {
        const uniqueMap = new Map<string, MatchResult>();
        results.forEach(r => uniqueMap.set(r.transaction.id, r));
        const uniqueResults = Array.from(uniqueMap.values());

        const incomeResults = uniqueResults.filter(r => 
            r.transaction.amount >= 0 || 
            r.status === ReconciliationStatus.PENDING
        );

        const expenseResults = uniqueResults.filter(r => 
            r.transaction.amount < 0 && 
            r.status !== ReconciliationStatus.PENDING
        );

        setReportPreviewData({
            income: groupResultsByChurch(incomeResults),
            expenses: { 'all_expenses_group': expenseResults }
        });
    }, []);

    /**
     * 🛡️ PIPELINE DE UPLOAD BLINDADO (V16)
     * Implementa Bloqueio de Reentrada e Deduplicação por Conteúdo (Chave Composta).
     */
    const handleStatementUpload = useCallback(async (content: string, fileName: string, bankId: string, rawFile?: File) => {
        // [Pipeline:LOCK_CHECK]
        if (isProcessingListaViva.current) {
            console.log("[Pipeline:LOCK_BLOCKED] Abortando execução paralela para evitar loop.");
            return;
        }

        console.log(`[Pipeline:START] Processando: ${fileName}`);
        isProcessingListaViva.current = true;
        setIsLoading(true);

        try {
            const result = await processFileContent(content, fileName, fileModels, customIgnoreKeywords);
            const incomingTransactions = result.transactions;

            if (incomingTransactions.length === 0) {
                showToast("Nenhuma transação encontrada.", "error");
                return;
            }

            // 🕵️ 2. GERAÇÃO DE CHAVE COMPOSTA ÚNICA
            const buildRowKey = (t: Transaction) => {
                const safeDate = t.date.trim();
                const safeName = t.description.trim().toLowerCase().replace(/\s+/g, ' ');
                const safeValue = Number(t.amount).toFixed(2);
                return `${safeDate}|${safeName}|${safeValue}`;
            };

            // 3. ÍNDICE REAL DOS EXISTENTES NA MEMÓRIA
            const existingFile = activeBankFiles.find(f => f.bankId === bankId);
            const existingTxs = existingFile?.processedTransactions || [];
            const existingKeys = new Set(existingTxs.map((t: Transaction) => buildRowKey(t)));

            // 4. FILTRO FORÇADO DE INSERT (Deduplicação de Conteúdo)
            const filteredNewTransactions = incomingTransactions.filter(t => {
                const rowKey = buildRowKey(t);
                if (existingKeys.has(rowKey)) {
                    console.log(`[ListaViva:DUPLICATE_BLOCKED] Linha já existente ignorada: ${rowKey}`);
                    return false;
                }
                existingKeys.add(rowKey);
                return true;
            });

            if (filteredNewTransactions.length === 0) {
                console.log("[ListaViva:NO_NEW_ROWS] Nenhuma nova transação para adicionar.");
                showToast("Todas as transações deste arquivo já estão na Lista Viva.", "error");
                return;
            }

            console.log(`[ListaViva:PERSIST_SAFE_COUNT] Preparando persistência de ${filteredNewTransactions.length} registros.`);

            // 5. PERSISTÊNCIA SEGURA (Fora do setter para evitar loop)
            await persistTransactions(bankId, filteredNewTransactions);

            // 6. ATUALIZAÇÃO DO ESTADO UI
            setBankStatementFile(prev => {
                const otherBanks = prev.filter(f => f.bankId !== bankId);
                const updatedTxs = [...existingTxs, ...filteredNewTransactions];

                return [...otherBanks, { 
                    bankId, 
                    content, 
                    fileName, 
                    rawFile, 
                    processedTransactions: updatedTxs,
                    appliedMethod: result.method
                }];
            });

            setSelectedBankIds(prev => prev.includes(bankId) ? prev : [...prev, bankId]);
            showToast(`${filteredNewTransactions.length} novas transações adicionadas.`, "success");

        } catch (error: any) {
            console.error("[Pipeline:ERROR]", error);
            showToast("Erro ao processar arquivo.", "error");
        } finally {
            setIsLoading(false);
            isProcessingListaViva.current = false; // [Pipeline:RELEASE_LOCK]
            console.log("[Pipeline:END]");
        }
    }, [activeBankFiles, fileModels, customIgnoreKeywords, persistTransactions, showToast, setIsLoading]);

    const handleContributorsUpload = useCallback((content: string, fileName: string, churchId: string) => {
        const church = churches.find(c => c.id === churchId);
        if (!church) return;

        const contributors = parseContributors(content, customIgnoreKeywords, contributionKeywords);
        if (contributors.length === 0) {
            showToast("Nenhum contribuinte encontrado.", "error");
            return;
        }

        setContributorFiles(prev => {
            const filtered = prev.filter(f => f.churchId !== churchId);
            return [...filtered, { church, churchId, contributors, fileName }];
        });
        showToast(`Lista carregada (${contributors.length} nomes).`, "success");
    }, [churches, customIgnoreKeywords, contributionKeywords, showToast]);

    const removeContributorFile = useCallback((churchId: string) => {
        setContributorFiles(prev => prev.filter(f => f.churchId !== churchId));
    }, []);

    const toggleBankSelection = useCallback((bankId: string) => {
        setSelectedBankIds(prev => prev.includes(bankId) ? prev.filter(id => id !== bankId) : [...prev, bankId]);
    }, []);

    const importGmailTransactions = useCallback(async (transactions: Transaction[]) => {
        if (!user || transactions.length === 0 || isProcessingListaViva.current) return;

        isProcessingListaViva.current = true;
        setIsLoading(true);
        try {
            const bankId = 'gmail-sync';
            const result = await IngestionOrchestrator.processVirtualData('Gmail', transactions, customIgnoreKeywords);

            await persistTransactions(bankId, result.transactions);

            setBankStatementFile(prev => [
                ...prev.filter(f => f.bankId !== bankId),
                { 
                    bankId, 
                    fileName: 'Sincronização Gmail', 
                    processedTransactions: result.transactions,
                    content: '',
                    fingerprint: result.fingerprint
                }
            ]);
            setSelectedBankIds(prev => prev.includes(bankId) ? prev : [...prev, bankId]);
            showToast("Gmail sincronizado.", "success");
        } catch (e) {
            showToast("Erro na sincronização.", "error");
        } finally {
            setIsLoading(false);
            isProcessingListaViva.current = false;
        }
    }, [user, customIgnoreKeywords, persistTransactions, showToast, setIsLoading]);

    const removeBankStatementFile = useCallback((bankId: string) => {
        setBankStatementFile(prev => prev.filter(f => f.bankId !== bankId));
        setSelectedBankIds(prev => prev.filter(id => id !== bankId));
        clearRemoteList(bankId);
    }, [clearRemoteList]);

    const handleCompare = useCallback(async (
        overrideType?: ComparisonType, 
        overrideSimilarity?: number, 
        overrideTolerance?: number
    ) => {
        if (isProcessingListaViva.current) return;
        isProcessingListaViva.current = true;
        setIsLoading(true);

        try {
            const selectedFiles = activeBankFiles.filter(f => selectedBankIds.includes(f.bankId));
            const allTransactionsMap = new Map<string, Transaction>();

            const rawTxs = activeReportId 
                ? matchResults.map(r => r.transaction) 
                : selectedFiles.flatMap(f => f.processedTransactions || []);

            rawTxs.forEach(tx => allTransactionsMap.set(tx.id, tx));
            const allTransactions = Array.from(allTransactionsMap.values());

            if (allTransactions.length === 0 && !activeReportId) {
                showToast("Sem dados para comparar.", "error");
                return;
            }

            const finalType = overrideType || comparisonType;
            const finalSimilarity = overrideSimilarity !== undefined ? overrideSimilarity : similarityLevel;
            const finalTolerance = overrideTolerance !== undefined ? overrideTolerance : dayTolerance;

            let transactionsToMatch = allTransactions;
            if (finalType === 'income') {
                transactionsToMatch = allTransactions.filter(tx => tx.amount >= 0);
            } else if (finalType === 'expenses') {
                transactionsToMatch = allTransactions.filter(tx => tx.amount < 0);
            }

            const results = matchTransactions(
                transactionsToMatch,
                contributorFiles,
                { similarityThreshold: finalSimilarity, dayTolerance: finalTolerance },
                learnedAssociations,
                churches,
                customIgnoreKeywords
            );

            setMatchResults(results);
            regenerateReportPreview(results);
            setHasActiveSession(true);
            if (!activeReportId) setActiveView('reports');
            showToast("Conciliação concluída!", "success");
        } catch (error) {
            console.error("Erro na comparação:", error);
            showToast("Erro na conciliação.", "error");
        } finally {
            setIsLoading(false);
            isProcessingListaViva.current = false;
        }
    }, [activeBankFiles, selectedBankIds, contributorFiles, similarityLevel, dayTolerance, comparisonType, learnedAssociations, churches, customIgnoreKeywords, activeReportId, matchResults, showToast, setIsLoading, setActiveView, regenerateReportPreview]);

    const updateReportData = useCallback((updatedRow: MatchResult) => {
        setMatchResults(prev => {
            const next = [...prev];
            const index = next.findIndex(r => r.transaction.id === updatedRow.transaction.id);
            if (index !== -1) {
                next[index] = updatedRow;
            } else {
                next.push(updatedRow);
            }
            regenerateReportPreview(next);
            return next;
        });
    }, [regenerateReportPreview]);

    const revertMatch = useCallback((txId: string) => {
        setMatchResults(prev => {
            const next = [...prev];
            const idx = next.findIndex(r => r.transaction.id === txId);
            if (idx === -1) return prev;
            const old = next[idx];
            next[idx] = { 
                ...old, 
                status: ReconciliationStatus.UNIDENTIFIED, 
                church: PLACEHOLDER_CHURCH, 
                contributor: null, 
                matchMethod: undefined, 
                similarity: 0,
                contributorAmount: undefined
            };
            regenerateReportPreview(next);
            return next;
        });
    }, [regenerateReportPreview]);

    const resetReconciliation = useCallback(async () => {
        setMatchResults([]);
        setReportPreviewData(null);
        setActiveReportId(null);
        setHasActiveSession(false);
        setBankStatementFile([]);
        setContributorFiles([]);
        setSelectedBankIds([]);
        await clearRemoteList();
        showToast("Sistema resetado.", "success");
        setActiveView('upload');
    }, [clearRemoteList, showToast, setActiveView]);

    const handleAnalyze = useCallback(async (tx: Transaction, contributors: Contributor[]) => {
        setUiFeedback(prev => ({ ...prev, loadingAiId: tx.id }));
        try {
            const name = await getAISuggestion(tx, contributors);
            setUiFeedback(prev => ({ ...prev, aiSuggestion: { id: tx.id, name }, loadingAiId: null }));
        } catch (e) {
            setUiFeedback(prev => ({ ...prev, loadingAiId: null }));
        }
    }, []);

    return {
        activeBankFiles, contributorFiles, matchResults, reportPreviewData,
        activeReportId, setActiveReportId, hasActiveSession, setHasActiveSession,
        comparisonType, setComparisonType, selectedBankIds,
        manualIdentificationTx, setManualIdentificationTx,
        bulkIdentificationTxs, setBulkIdentificationTxs,
        importGmailTransactions,
        ...uiFeedback,
        setUiFeedback,
        handleStatementUpload, handleContributorsUpload, removeBankStatementFile,
        removeContributorFile, toggleBankSelection, handleCompare, resetReconciliation,
        revertMatch, updateReportData, handleAnalyze, setMatchResults, setReportPreviewData,
        setBankStatementFile,
        closeManualIdentify: () => {
            setManualIdentificationTx(null);
            setBulkIdentificationTxs([]);
        },
        findMatchResult: (id: string) => matchResults.find(r => r.transaction.id === id),
        removeTransaction: (id: string) => {
            setMatchResults(prev => {
                const next = prev.filter(r => r.transaction.id !== id);
                regenerateReportPreview(next);
                return next;
            });
        }
    };
};

import { useEffect, useCallback, useRef } from 'react';
import { Transaction } from '../types';
import { consolidationService } from '../services/ConsolidationService';

interface UseLiveListSyncProps {
    user: any;
    setBankStatementFile: (fn: (prev: any[]) => any[]) => void;
    setSelectedBankIds: (fn: (prev: string[]) => string[]) => void;
    showToast?: (msg: string, type: 'success' | 'error') => void;
}

export const useLiveListSync = ({
    user,
    setBankStatementFile,
    setSelectedBankIds,
    showToast
}: UseLiveListSyncProps) => {
    const isHydrating = useRef(false);
    const hasHydrated = useRef(false);
    const lastUserId = useRef<string | null>(null);

    // --- HIDRATAÇÃO: Recupera do DB ao iniciar ---
    useEffect(() => {
        if (!user || isHydrating.current || (hasHydrated.current && lastUserId.current === user.id)) return;

        const hydrate = async () => {
            isHydrating.current = true;
            lastUserId.current = user.id;

            try {
                console.log(`[Lista Viva] Iniciando recuperação para usuário: ${user.id}`);
                const dbTransactions = await consolidationService.getPendingTransactions(user.id);

                if (!dbTransactions || dbTransactions.length === 0) {
                    hasHydrated.current = true;
                    isHydrating.current = false;
                    return;
                }

                const groupedByBank: Record<string, Transaction[]> = {};
                const safeTransactions = dbTransactions.slice(0, 3000);

                safeTransactions.forEach((t: any) => {
                    const bankId = t.bank_id || 'unknown';
                    const tx: Transaction = {
                        id: t.id,
                        date: t.transaction_date,
                        description: t.description,
                        rawDescription: t.description,
                        amount: t.amount,
                        originalAmount: String(t.amount.toFixed(2)),
                        contributionType: t.type === 'income' ? 'ENTRADA' : 'SAÍDA',
                        cleanedDescription: t.description
                    };
                    if (!groupedByBank[bankId]) groupedByBank[bankId] = [];
                    groupedByBank[bankId].push(tx);
                });

                const restoredFiles = Object.entries(groupedByBank).map(([bankId, txs]) => ({
                    bankId,
                    content: '',
                    fileName: `Lista Viva (Recuperada)`,
                    rawFile: undefined,
                    processedTransactions: txs,
                    isRestored: true
                }));

                setBankStatementFile(() => restoredFiles);
                setSelectedBankIds(() => restoredFiles.map(f => f.bankId));

                hasHydrated.current = true;
                console.log(`[Lista Viva] ${safeTransactions.length} registros restaurados.`);
            } catch (err) {
                console.error("[Lista Viva] Erro crítico na hidratação:", err);
            } finally {
                isHydrating.current = false;
            }
        };

        hydrate();
    }, [user, setBankStatementFile, setSelectedBankIds]);

    /**
     * 🛡️ PERSISTÊNCIA BLINDADA COM CHAVE COMPOSTA (V17)
     */
    const persistTransactions = useCallback(async (bankId: string, transactions: Transaction[]) => {
        if (!user || transactions.length === 0) return;

        try {
            // 1. OBTER ESTADO ATUAL REMOTO PARA DEDUPLICAÇÃO REAL
            const currentDbTxs = await consolidationService.getPendingTransactions(user.id);

            // Função Interna de Chave Composta Estrita
            const buildKey = (date: string, desc: string, amt: number) => {
                const d = date.trim();
                const n = desc.trim().toLowerCase().replace(/\s+/g, ' ');
                const v = Number(amt).toFixed(2);
                return `${d}|${n}|${v}`;
            };

            const existingKeysMap = new Map();
            currentDbTxs.forEach((t: any) => {
                existingKeysMap.set(buildKey(t.transaction_date, t.description, t.amount), true);
            });

            // 2. FILTRAR LOTE (Insert Guard)
            const uniqueToPersist = transactions.filter(t => {
                const rowKey = buildKey(t.date, t.description, t.amount);
                if (existingKeysMap.has(rowKey)) {
                    console.log(`[ListaViva:DUPLICATE_BLOCKED] Persistência bloqueada: ${rowKey}`);
                    return false;
                }
                existingKeysMap.set(rowKey, true); // Evita duplicatas internas do lote
                return true;
            });

            if (uniqueToPersist.length === 0) {
                console.log("[ListaViva:NO_NEW_ROWS] Nenhuma linha inédita para gravar no banco.");
                return;
            }

            console.log(`[ListaViva:PERSIST_SAFE_COUNT] Persistindo ${uniqueToPersist.length} registros únicos.`);

            // 3. BATCH INSERT
            const chunkSize = 100;
            for (let i = 0; i < uniqueToPersist.length; i += chunkSize) {
                const chunk = uniqueToPersist.slice(i, i + chunkSize);
                const data = chunk.map(t => ({
                    transaction_date: t.date,
                    amount: t.amount,
                    description: t.description,
                    type: (t.amount >= 0 ? 'income' : 'expense') as 'income' | 'expense',
                    pix_key: null,
                    source: 'file' as 'file',
                    user_id: user.id,
                    bank_id: bankId.length > 10 ? bankId : null 
                }));
                await consolidationService.addTransactions(data);
            }
        } catch (e) {
            console.warn("[ListaViva:PERSIST_ERROR] Erro na sincronização remota", e);
        }
    }, [user]);

    const clearRemoteList = useCallback(async (bankId?: string) => {
        if (!user) return;
        try {
            await consolidationService.deletePendingTransactions(user.id, bankId);
            hasHydrated.current = false;
        } catch (e) {
            console.error("[Lista Viva] Erro ao limpar banco remoto:", e);
        }
    }, [user]);

    return { persistTransactions, clearRemoteList };
};

import { useState, useCallback, useRef } from 'react';
import { 
    MatchResult, 
    Transaction, 
    Contributor, 
    Church, 
    Bank, 
    FileModel, 
    ComparisonType,
    ContributorFile,
    GroupedReportData,
    ReconciliationStatus
} from '../types';
import { 
    processFileContent, 
    parseContributors, 
    matchTransactions, 
    groupResultsByChurch,
    PLACEHOLDER_CHURCH
} from '../services/processingService';
import { IngestionOrchestrator } from '../core/engine/IngestionOrchestrator';
import { getAISuggestion } from '../services/geminiService';
import { useLiveListSync } from './useLiveListSync';

interface UseReconciliationProps {
    user: any;
    churches: Church[];
    banks: Bank[];
    fileModels: FileModel[];
    similarityLevel: number;
    dayTolerance: number;
    customIgnoreKeywords: string[];
    contributionKeywords: string[];
    learnedAssociations: any[];
    showToast: (msg: string, type: 'success' | 'error') => void;
    setIsLoading: (loading: boolean) => void;
    setActiveView: (view: any) => void;
}

export const useReconciliation = ({
    user,
    churches,
    banks,
    fileModels,
    similarityLevel,
    dayTolerance,
    customIgnoreKeywords,
    contributionKeywords,
    learnedAssociations,
    showToast,
    setIsLoading,
    setActiveView
}: UseReconciliationProps) => {

    const [activeBankFiles, setBankStatementFile] = useState<any[]>([]);
    const [contributorFiles, setContributorFiles] = useState<ContributorFile[]>([]);
    const [selectedBankIds, setSelectedBankIds] = useState<string[]>([]);
    const [matchResults, setMatchResults] = useState<MatchResult[]>([]);
    const [reportPreviewData, setReportPreviewData] = useState<{ income: GroupedReportData; expenses: GroupedReportData } | null>(null);
    const [activeReportId, setActiveReportId] = useState<string | null>(null);
    const [hasActiveSession, setHasActiveSession] = useState(false);
    const [comparisonType, setComparisonType] = useState<ComparisonType>('income');
    const [manualIdentificationTx, setManualIdentificationTx] = useState<Transaction | null>(null);
    const [bulkIdentificationTxs, setBulkIdentificationTxs] = useState<Transaction[]>([]);

    // 🔒 1) BLOQUEIO DE REENTRADA DO PIPELINE
    const isProcessingListaViva = useRef(false);

    const [uiFeedback, setUiFeedback] = useState({
        loadingAiId: null as string | null,
        aiSuggestion: null as { id: string; name: string } | null,
        isRecompareModalOpen: false,
        pendingTraining: null as any | null
    });

    const { persistTransactions, clearRemoteList } = useLiveListSync({
        user,
        setBankStatementFile,
        setSelectedBankIds,
        showToast
    });

    const regenerateReportPreview = useCallback((results: MatchResult[]) => {
        const uniqueMap = new Map<string, MatchResult>();
        results.forEach(r => uniqueMap.set(r.transaction.id, r));
        const uniqueResults = Array.from(uniqueMap.values());

        const incomeResults = uniqueResults.filter(r => 
            r.transaction.amount >= 0 || 
            r.status === ReconciliationStatus.PENDING
        );

        const expenseResults = uniqueResults.filter(r => 
            r.transaction.amount < 0 && 
            r.status !== ReconciliationStatus.PENDING
        );

        setReportPreviewData({
            income: groupResultsByChurch(incomeResults),
            expenses: { 'all_expenses_group': expenseResults }
        });
    }, []);

    /**
     * 🛡️ PIPELINE DE UPLOAD BLINDADO (V18)
     * Resolve Loop de Execução e Impede Duplicação de Linhas via Chave Composta.
     */
    const handleStatementUpload = useCallback(async (content: string, fileName: string, bankId: string, rawFile?: File) => {
        // [Pipeline:LOCK_CHECK]
        if (isProcessingListaViva.current) {
            console.log("[Pipeline:LOCK_BLOCKED] Abortando: O pipeline já está em execução.");
            return;
        }

        console.log(`[Pipeline:START] Processando conteúdo: ${fileName}`);
        isProcessingListaViva.current = true;
        setIsLoading(true);

        try {
            // 2) GERAÇÃO DE CHAVE ÚNICA COMPOSTA NA LISTA VIVA
            const normalize = (text: string) => text?.trim().toLowerCase().replace(/\s+/g, ' ') || '';
            const buildRowKey = (date: string, desc: string, amt: number) => {
                const safeDate = normalize(date);
                const safeName = normalize(desc);
                const safeValue = Number(amt).toFixed(2);
                return `${safeDate}|${safeName}|${safeValue}`;
            };

            const result = await processFileContent(content, fileName, fileModels, customIgnoreKeywords);
            const incomingTransactions = result.transactions;

            if (incomingTransactions.length === 0) {
                showToast("Nenhuma transação encontrada no arquivo.", "error");
                return;
            }

            // 3) ÍNDICE REAL DOS EXISTENTES (Compara linha a linha na memória)
            const currentBankFile = activeBankFiles.find(f => f.bankId === bankId);
            const existingTxs = currentBankFile?.processedTransactions || [];
            const existingMap = new Map();
            existingTxs.forEach((t: Transaction) => {
                existingMap.set(buildRowKey(t.date, t.description, t.amount), true);
            });

            // 4) FILTRO FORÇADO DE INSERT
            const filteredNewRows = incomingTransactions.filter(t => {
                const key = buildRowKey(t.date, t.description, t.amount);
                if (existingMap.has(key)) {
                    console.log(`[ListaViva:DUPLICATE_BLOCKED] Linha ignorada por duplicidade: ${key}`);
                    return false;
                }
                existingMap.set(key, true);
                return true;
            });

            if (filteredNewRows.length === 0) {
                console.log("[ListaViva:NO_NEW_ROWS] O arquivo não contém novas linhas únicas.");
                showToast("Todas as linhas deste arquivo já estão na lista.", "error");
                return;
            }

            console.log(`[ListaViva:PERSIST_SAFE_COUNT] Persistindo ${filteredNewRows.length} linhas únicas.`);

            // 5) BLOQUEIO DE DUPLICAÇÃO NO STORAGE (Chamada assíncrona isolada)
            await persistTransactions(bankId, filteredNewRows);

            // 6) ATUALIZAÇÃO DO ESTADO UI
            setBankStatementFile(prev => {
                const otherBanks = prev.filter(f => f.bankId !== bankId);
                const updatedTxs = [...existingTxs, ...filteredNewRows];

                return [...otherBanks, { 
                    bankId, 
                    content, 
                    fileName, 
                    rawFile, 
                    processedTransactions: updatedTxs,
                    appliedMethod: result.method
                }];
            });

            setSelectedBankIds(prev => prev.includes(bankId) ? prev : [...prev, bankId]);
            showToast(`${filteredNewRows.length} novas linhas adicionadas à Lista Viva.`, "success");

        } catch (error: any) {
            console.error("[Pipeline:ERROR]", error);
            showToast("Erro durante o processamento.", "error");
        } finally {
            setIsLoading(false);
            isProcessingListaViva.current = false; // [Pipeline:FINALLY] Liberar trava
            console.log("[Pipeline:END]");
        }
    }, [activeBankFiles, fileModels, customIgnoreKeywords, persistTransactions, showToast, setIsLoading]);

    const handleContributorsUpload = useCallback((content: string, fileName: string, churchId: string) => {
        const church = churches.find(c => c.id === churchId);
        if (!church) return;

        const contributors = parseContributors(content, customIgnoreKeywords, contributionKeywords);
        if (contributors.length === 0) {
            showToast("Nenhum contribuinte encontrado.", "error");
            return;
        }

        setContributorFiles(prev => {
            const filtered = prev.filter(f => f.churchId !== churchId);
            return [...filtered, { church, churchId, contributors, fileName }];
        });
        showToast(`Lista carregada (${contributors.length} nomes).`, "success");
    }, [churches, customIgnoreKeywords, contributionKeywords, showToast]);

    const removeContributorFile = useCallback((churchId: string) => {
        setContributorFiles(prev => prev.filter(f => f.churchId !== churchId));
    }, []);

    const toggleBankSelection = useCallback((bankId: string) => {
        setSelectedBankIds(prev => prev.includes(bankId) ? prev.filter(id => id !== bankId) : [...prev, bankId]);
    }, []);

    const importGmailTransactions = useCallback(async (transactions: Transaction[]) => {
        if (!user || transactions.length === 0 || isProcessingListaViva.current) return;

        isProcessingListaViva.current = true;
        setIsLoading(true);
        try {
            const bankId = 'gmail-sync';
            const result = await IngestionOrchestrator.processVirtualData('Gmail', transactions, customIgnoreKeywords);

            await persistTransactions(bankId, result.transactions);

            setBankStatementFile(prev => [
                ...prev.filter(f => f.bankId !== bankId),
                { 
                    bankId, 
                    fileName: 'Sincronização Gmail', 
                    processedTransactions: result.transactions,
                    content: '',
                    fingerprint: result.fingerprint
                }
            ]);
            setSelectedBankIds(prev => prev.includes(bankId) ? prev : [...prev, bankId]);
            showToast("Gmail sincronizado.", "success");
        } catch (e) {
            showToast("Erro na sincronização.", "error");
        } finally {
            setIsLoading(false);
            isProcessingListaViva.current = false;
        }
    }, [user, customIgnoreKeywords, persistTransactions, showToast, setIsLoading]);

    const removeBankStatementFile = useCallback((bankId: string) => {
        setBankStatementFile(prev => prev.filter(f => f.bankId !== bankId));
        setSelectedBankIds(prev => prev.filter(id => id !== bankId));
        clearRemoteList(bankId);
    }, [clearRemoteList]);

    const handleCompare = useCallback(async (
        overrideType?: ComparisonType, 
        overrideSimilarity?: number, 
        overrideTolerance?: number
    ) => {
        if (isProcessingListaViva.current) return;
        isProcessingListaViva.current = true;
        setIsLoading(true);

        try {
            const selectedFiles = activeBankFiles.filter(f => selectedBankIds.includes(f.bankId));
            const allTransactionsMap = new Map<string, Transaction>();

            const rawTxs = activeReportId 
                ? matchResults.map(r => r.transaction) 
                : selectedFiles.flatMap(f => f.processedTransactions || []);

            rawTxs.forEach(tx => allTransactionsMap.set(tx.id, tx));
            const allTransactions = Array.from(allTransactionsMap.values());

            if (allTransactions.length === 0 && !activeReportId) {
                showToast("Sem dados para comparar.", "error");
                return;
            }

            const finalType = overrideType || comparisonType;
            const finalSimilarity = overrideSimilarity !== undefined ? overrideSimilarity : similarityLevel;
            const finalTolerance = overrideTolerance !== undefined ? overrideTolerance : dayTolerance;

            let transactionsToMatch = allTransactions;
            if (finalType === 'income') {
                transactionsToMatch = allTransactions.filter(tx => tx.amount >= 0);
            } else if (finalType === 'expenses') {
                transactionsToMatch = allTransactions.filter(tx => tx.amount < 0);
            }

            const results = matchTransactions(
                transactionsToMatch,
                contributorFiles,
                { similarityThreshold: finalSimilarity, dayTolerance: finalTolerance },
                learnedAssociations,
                churches,
                customIgnoreKeywords
            );

            setMatchResults(results);
            regenerateReportPreview(results);
            setHasActiveSession(true);
            if (!activeReportId) setActiveView('reports');
            showToast("Conciliação concluída!", "success");
        } catch (error) {
            console.error("Erro na comparação:", error);
            showToast("Erro na conciliação.", "error");
        } finally {
            setIsLoading(false);
            isProcessingListaViva.current = false;
        }
    }, [activeBankFiles, selectedBankIds, contributorFiles, similarityLevel, dayTolerance, comparisonType, learnedAssociations, churches, customIgnoreKeywords, activeReportId, matchResults, showToast, setIsLoading, setActiveView, regenerateReportPreview]);

    const updateReportData = useCallback((updatedRow: MatchResult) => {
        setMatchResults(prev => {
            const next = [...prev];
            const index = next.findIndex(r => r.transaction.id === updatedRow.transaction.id);
            if (index !== -1) {
                next[index] = updatedRow;
            } else {
                next.push(updatedRow);
            }
            regenerateReportPreview(next);
            return next;
        });
    }, [regenerateReportPreview]);

    const revertMatch = useCallback((txId: string) => {
        setMatchResults(prev => {
            const next = [...prev];
            const idx = next.findIndex(r => r.transaction.id === txId);
            if (idx === -1) return prev;
            const old = next[idx];
            next[idx] = { 
                ...old, 
                status: ReconciliationStatus.UNIDENTIFIED, 
                church: PLACEHOLDER_CHURCH, 
                contributor: null, 
                matchMethod: undefined, 
                similarity: 0,
                contributorAmount: undefined
            };
            regenerateReportPreview(next);
            return next;
        });
    }, [regenerateReportPreview]);

    const resetReconciliation = useCallback(async () => {
        setMatchResults([]);
        setReportPreviewData(null);
        setActiveReportId(null);
        setHasActiveSession(false);
        setBankStatementFile([]);
        setContributorFiles([]);
        setSelectedBankIds([]);
        await clearRemoteList();
        showToast("Sistema resetado.", "success");
        setActiveView('upload');
    }, [clearRemoteList, showToast, setActiveView]);

    const handleAnalyze = useCallback(async (tx: Transaction, contributors: Contributor[]) => {
        setUiFeedback(prev => ({ ...prev, loadingAiId: tx.id }));
        try {
            const name = await getAISuggestion(tx, contributors);
            setUiFeedback(prev => ({ ...prev, aiSuggestion: { id: tx.id, name }, loadingAiId: null }));
        } catch (e) {
            setUiFeedback(prev => ({ ...prev, loadingAiId: null }));
        }
    }, []);

    return {
        activeBankFiles, contributorFiles, matchResults, reportPreviewData,
        activeReportId, setActiveReportId, hasActiveSession, setHasActiveSession,
        comparisonType, setComparisonType, selectedBankIds,
        manualIdentificationTx, setManualIdentificationTx,
        bulkIdentificationTxs, setBulkIdentificationTxs,
        importGmailTransactions,
        ...uiFeedback,
        setUiFeedback,
        handleStatementUpload, handleContributorsUpload, removeBankStatementFile,
        removeContributorFile, toggleBankSelection, handleCompare, resetReconciliation,
        revertMatch, updateReportData, handleAnalyze, setMatchResults, setReportPreviewData,
        setBankStatementFile,
        closeManualIdentify: () => {
            setManualIdentificationTx(null);
            setBulkIdentificationTxs([]);
        },
        findMatchResult: (id: string) => matchResults.find(r => r.transaction.id === id),
        removeTransaction: (id: string) => {
            setMatchResults(prev => {
                const next = prev.filter(r => r.transaction.id !== id);
                regenerateReportPreview(next);
                return next;
            });
        }
    };
};

